const body = $input.first().json;

const required = [
  { path: 'process_id', val: body.process_id },
  { path: 'membership_id', val: body.membership_id },
  { path: 'user.id', val: body.user?.id },
  { path: 'user.email', val: body.user?.email },
  { path: 'organization.id', val: body.organization?.id },
];

const missing = required.filter(f => !f.val).map(f => f.path);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

return [{
  json: {
    process_id: body.process_id,
    membership_id: body.membership_id,
    user: body.user,
    organization: body.organization,
    event: body.event ?? 'user.invited',
    validated_at: new Date().toISOString(),
  }
}];

const response = $input.first().json;
const statusCode = response.statusCode ?? response.status ?? 200;

// If member already exists and is active, skip provisioning
if (statusCode === 200 && response.body?.status === 'active') {
  return [{
    json: {
      already_provisioned: true,
      membership_id: response.body.id,
      message: 'User already provisioned — idempotent skip',
      skipped_at: new Date().toISOString(),
    }
  }];
}

// Pass through for provisioning
const prev = $('Validate Input').first().json;
return [{
  json: {
    ...prev,
    already_provisioned: false,
  }
}];

// Stub: In production, replace with n8n-nodes-base.emailSend
// or integrate with SendGrid/SES via httpRequest
const input = $input.first().json;

if (input.already_provisioned) {
  return [{ json: { ...input, email_sent: false, email_skipped: true } }];
}

const emailPayload = {
  to: input.user.email,
  subject: `Einladung zur AI-Native Workspace Platform`,
  body: `Hallo ${input.user.display_name ?? input.user.email},\n\nSie wurden zu einer Organisation eingeladen.\n\nBitte klicken Sie auf den folgenden Link, um Ihr Konto zu aktivieren:\n${process.env.APP_URL ?? 'https://app.platform.local'}/accept-invitation?token=${input.membership_id}\n\nDiese Einladung ist 7 Tage gültig.\n\nMit freundlichen Grüßen,\nDas Platform Team`,
  html: `<h2>Einladung</h2><p>Sie wurden eingeladen. <a href="${process.env.APP_URL ?? 'https://app.platform.local'}/accept-invitation?token=${input.membership_id}">Jetzt aktivieren</a></p>`,
};

console.log('Email stub — would send:', JSON.stringify(emailPayload));

return [{
  json: {
    ...input,
    email_sent: true,
    email_payload: emailPayload,
    email_sent_at: new Date().toISOString(),
  }
}];

// Emit user.provisioned event via Redis Pub/Sub (stubbed as HTTP call)
const input = $('Send Invitation Email').first().json;

const event = {
  event_type: 'user.provisioned',
  process_id: input.process_id,
  membership_id: input.membership_id,
  organization_id: input.organization.id,
  user_id: input.user.id,
  email_sent: input.email_sent,
  provisioned_at: new Date().toISOString(),
  source: 'n8n:user-provisioning',
};

// In production: POST to internal event bus / Redis HTTP bridge
console.log('Event emitted:', JSON.stringify(event));

return [{ json: { ...input, event_emitted: event } }];

const error = $input.first().json;
console.error('user-provisioning workflow error:', JSON.stringify({
  execution_id: $execution.id,
  error: error.message ?? error,
  timestamp: new Date().toISOString(),
}));

return [{
  json: {
    status: 'failed',
    error: error.message ?? String(error),
    execution_id: $execution.id,
    failed_at: new Date().toISOString(),
  }
}];
